patch:
diff --git a/llvm/lib/Transforms/IPO/GlobalOpt.cpp b/llvm/lib/Transforms/IPO/GlobalOpt.cpp
index cfba8dcc05b2..95f793a16754 100644
--- a/llvm/lib/Transforms/IPO/GlobalOpt.cpp
+++ b/llvm/lib/Transforms/IPO/GlobalOpt.cpp
@@ -968,7 +968,7 @@ OptimizeGlobalAddressOfAllocation(GlobalVariable *GV, CallInst *CI,
       auto *NewSI = new StoreInst(
           ConstantInt::getBool(GV->getContext(), !isa<ConstantPointerNull>(
                                                      SI->getValueOperand())),
-          InitBool, false, Align(1), SI->getOrdering(), SI->getSyncScopeID(),
+          InitBool, false, Align(1), AtomicOrdering::NotAtomic, SI->getSyncScopeID(),
           SI->getIterator());
       NewSI->setDebugLoc(SI->getDebugLoc());
       SI->eraseFromParent();
@@ -987,7 +987,7 @@ OptimizeGlobalAddressOfAllocation(GlobalVariable *GV, CallInst *CI,
       // Replace the cmp X, 0 with a use of the bool value.
       Value *LV = new LoadInst(InitBool->getValueType(), InitBool,
                                InitBool->getName() + ".val", false, Align(1),
-                               LI->getOrdering(), LI->getSyncScopeID(),
+                               AtomicOrdering::NotAtomic, LI->getSyncScopeID(),
                                LI->getIterator());
       // FIXME: Should we use the DebugLoc of the load used by the predicate, or
       // the predicate? The load seems most appropriate, but there's an argument
@@ -1114,6 +1114,18 @@ static bool tryToOptimizeStoreOfAllocationToGlobal(GlobalVariable *GV,
   if (!allUsesOfLoadedValueWillTrapIfNull(GV))
     return false;

+  // Check if any store or load to the global is atomic. Atomic operations
+  // have stricter memory ordering semantics that may not be preserved by
+  // the transformation.
+  SmallVector<Value *, 4> Guses;
+  allUsesOfLoadAndStores(GV, Guses);
+  for (auto *U : Guses) {
+    if (auto *SI = dyn_cast<StoreInst>(U))
+      if (SI->isAtomic()) return false;
+    if (auto *LI = dyn_cast<LoadInst>(U))
+      if (LI->isAtomic()) return false;
+  }
+
   // We can't optimize this if the malloc itself is used in a complex way,
   // for example, being stored into multiple globals.  This allows the
   // malloc to be stored into the specified global, loaded, gep, icmp'd.

